// Frontend (React)
function UserList() {
  const [users, setUsers] = useState([]);
  useEffect(() => {
    fetch('/api/users').then(res => res.json())
      .then(data => setUsers(data));
  }, []);
  return (
    <ul>{users.map(user => (
      <li key={user._id}>{user.name}</li>
    ))}</ul>
  );
}

